import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the input does not exceed the buffer size
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < name.length() && i < bufferSize; i++) {
            buffer[i] = name.charAt(i);
        }

        // Print out the contents of the buffer
        System.out.print("Buffer contents: ");
        for (int i = 0; i < buffer.length; i++) {
            if (buffer[i] != '\u0000') { // Check for null character to avoid printing uninitialized data
                System.out.print(buffer[i]);
            }
        }
    }

}

